diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..0c6871bd0c21 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7768,43 +7768,85 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,
 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
-    return nullptr;
+  bool IsSelectFabs = false;
+
+  // Match fabs intrinsic or select-based fabs pattern.
+  if (!match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // Try to match select-based fabs or -fabs patterns.
+    // Both fabs(X) and -fabs(X) give the same result when comparing to 0.0,
+    // so we can accept either.
+    // Patterns:
+    //   select (fcmp oge/ugt X, 0.0), X, fneg(X)  ->  fabs(X)
+    //   select (fcmp ole/ult X, 0.0), fneg(X), X  ->  fabs(X)
+    //   select (fcmp oge/ugt X, 0.0), fneg(X), X  ->  -fabs(X)
+    //   select (fcmp ole/ult X, 0.0), X, fneg(X)  ->  -fabs(X)
+    Value *Cond, *TVal, *FVal;
+    if (!match(I.getOperand(0), m_Select(m_Value(Cond), m_Value(TVal),
+                                         m_Value(FVal))))
+      return nullptr;
+
+    CmpInst::Predicate Pred;
+    if (!match(Cond, m_FCmp(Pred, m_Value(X), m_AnyZeroFP())))
+      return nullptr;
+
+    bool IsGE = Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OGT ||
+                Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_UGT;
+    bool IsLE = Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_OLT ||
+                Pred == FCmpInst::FCMP_ULE || Pred == FCmpInst::FCMP_ULT;
+
+    bool Matched = false;
+    // Check for (X >= 0) ? X : -X  or  (X <= 0) ? X : -X
+    if (TVal == X && match(FVal, m_FNeg(m_Specific(X))))
+      Matched = IsGE || IsLE;
+    // Check for (X >= 0) ? -X : X  or  (X <= 0) ? -X : X
+    else if (FVal == X && match(TVal, m_FNeg(m_Specific(X))))
+      Matched = IsGE || IsLE;
+
+    if (!Matched)
+      return nullptr;
+
+    IsSelectFabs = true;
+  }

   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))
     return nullptr;

-  if (!C->isPosZero()) {
+  if (!C->isZero()) {
+    // For select-based fabs, we only handle comparisons to zero.
+    if (IsSelectFabs)
+      return nullptr;
+
+    // For fabs intrinsic, check if this is a denormal comparison.
     if (!C->isSmallestNormalized())
       return nullptr;

     const Function *F = I.getFunction();
     DenormalMode Mode = F->getDenormalMode(C->getSemantics());
-    if (Mode.Input == DenormalMode::PreserveSign ||
-        Mode.Input == DenormalMode::PositiveZero) {
+    if (Mode.Input != DenormalMode::PreserveSign &&
+        Mode.Input != DenormalMode::PositiveZero)
+      return nullptr;

-      auto replaceFCmp = [](FCmpInst *I, FCmpInst::Predicate P, Value *X) {
-        Constant *Zero = ConstantFP::getZero(X->getType());
-        return new FCmpInst(P, X, Zero, "", I);
-      };
+    auto replaceFCmp = [](FCmpInst *I, FCmpInst::Predicate P, Value *X) {
+      Constant *Zero = ConstantFP::getZero(X->getType());
+      return new FCmpInst(P, X, Zero, "", I);
+    };

-      switch (I.getPredicate()) {
-      case FCmpInst::FCMP_OLT:
-        // fcmp olt fabs(x), smallest_normalized_number -> fcmp oeq x, 0.0
-        return replaceFCmp(&I, FCmpInst::FCMP_OEQ, X);
-      case FCmpInst::FCMP_UGE:
-        // fcmp uge fabs(x), smallest_normalized_number -> fcmp une x, 0.0
-        return replaceFCmp(&I, FCmpInst::FCMP_UNE, X);
-      case FCmpInst::FCMP_OGE:
-        // fcmp oge fabs(x), smallest_normalized_number -> fcmp one x, 0.0
-        return replaceFCmp(&I, FCmpInst::FCMP_ONE, X);
-      case FCmpInst::FCMP_ULT:
-        // fcmp ult fabs(x), smallest_normalized_number -> fcmp ueq x, 0.0
-        return replaceFCmp(&I, FCmpInst::FCMP_UEQ, X);
-      default:
-        break;
-      }
+    switch (I.getPredicate()) {
+    case FCmpInst::FCMP_OLT:
+      // fcmp olt fabs(x), smallest_normalized_number -> fcmp oeq x, 0.0
+      return replaceFCmp(&I, FCmpInst::FCMP_OEQ, X);
+    case FCmpInst::FCMP_UGE:
+      // fcmp uge fabs(x), smallest_normalized_number -> fcmp une x, 0.0
+      return replaceFCmp(&I, FCmpInst::FCMP_UNE, X);
+    case FCmpInst::FCMP_OGE:
+      // fcmp oge fabs(x), smallest_normalized_number -> fcmp one x, 0.0
+      return replaceFCmp(&I, FCmpInst::FCMP_ONE, X);
+    case FCmpInst::FCMP_ULT:
+      // fcmp ult fabs(x), smallest_normalized_number -> fcmp ueq x, 0.0
+      return replaceFCmp(&I, FCmpInst::FCMP_UEQ, X);
+    default:
+      break;
     }

     return nullptr;

